// plane/git/storage/hot/writer.go
package hot

import (
    "context"

    "github.com/klauspost/reedsolomon"
)

type Writer struct {
    persistShards func(ctx context.Context, key string, shards [][]byte) error
}

func (w *Writer) Put(ctx context.Context, key string, obj []byte) error {
    enc, err := reedsolomon.New(10, 4)
    if err != nil {
        return err
    }
    shards, err := enc.Split(obj)
    if err != nil {
        return err
    }
    if err := enc.Encode(shards); err != nil {
        return err
    }
    return w.persistShards(ctx, key, shards)
}
